"use client"

import { useState } from "react"
import Link from "next/link"
import { OptimizedImage } from "@/components/ui/OptimizedImage"
import { Button } from "@/components/atoms/Button/Button"
import { useCustomer } from "@/hooks/useCustomer"
import { 
  Heart, 
  Eye, 
  Copy, 
  Calendar,
  DollarSign,
  Layers,
  User,
  Lock,
  Globe,
  Edit,
  Share,
  Download,
  ArrowLeft
} from "lucide-react"

interface Props {
  deck: any
}

export function DeckViewPage({ deck }: Props) {
  const [liked, setLiked] = useState(false)
  const [likeCount, setLikeCount] = useState(deck.stats?.likes || 0)
  const { customer, isAuthenticated } = useCustomer()
  
  const isOwner = isAuthenticated && customer && deck.userId === customer.id
  
  const formatDate = (date: string | Date) => {
    const d = new Date(date)
    return d.toLocaleDateString('en-US', { 
      month: 'long', 
      day: 'numeric', 
      year: 'numeric' 
    })
  }

  const handleLike = async () => {
    if (!isAuthenticated) return
    
    try {
      // Toggle like state optimistically
      setLiked(!liked)
      setLikeCount((prev: number) => liked ? prev - 1 : prev + 1)
      
      // TODO: Implement actual like API call
      // await customerBackendAPI.likeDeck(deck.id, !liked)
    } catch (error) {
      // Revert on error
      setLiked(!liked)
      setLikeCount((prev: number) => liked ? prev + 1 : prev - 1)
      console.error('Failed to update like:', error)
    }
  }

  const handleCopy = async () => {
    if (!isAuthenticated) return
    
    try {
      // TODO: Implement deck copying
      console.log('Copy deck:', deck.id)
    } catch (error) {
      console.error('Failed to copy deck:', error)
    }
  }

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: deck.name,
          text: deck.description || `Check out this ${deck.game} deck`,
          url: window.location.href
        })
      } catch (error) {
        // User cancelled or error occurred
      }
    } else {
      // Fallback to copying URL
      try {
        await navigator.clipboard.writeText(window.location.href)
        // TODO: Show toast notification
      } catch (error) {
        console.error('Failed to copy URL:', error)
      }
    }
  }

  return (
    <div className="max-w-6xl mx-auto px-4 md:px-8 py-8">
      {/* Header */}
      <div className="mb-6">
        <Link
          href="/decks"
          className="inline-flex items-center gap-2 mb-4 text-sm transition-colors"
          style={{ color: "var(--text-secondary, #B8B0D8)" }}
        >
          <ArrowLeft className="h-4 w-4" />
          Back to Decks
        </Link>

        <div className="flex flex-col lg:flex-row lg:items-start lg:justify-between gap-6">
          <div className="flex-1">
            <div className="flex items-center gap-3 mb-2">
              <h1
                className="font-barlow-condensed font-bold"
                style={{ fontSize: 32, color: "var(--text-primary, #F0EEFF)" }}
              >
                {deck.name}
              </h1>
              <span
                className="inline-flex items-center text-xs font-medium px-2.5 py-1 rounded-full"
                style={deck.isPublic
                  ? { background: "rgba(16, 185, 129, 0.15)", color: "var(--positive, #10B981)", border: "1px solid rgba(16, 185, 129, 0.25)" }
                  : { background: "var(--bg-surface-3, #2C2A4A)", color: "var(--text-secondary, #B8B0D8)", border: "1px solid var(--border-default, #2C2A4A)" }
                }
              >
                {deck.isPublic ? <Globe className="w-3 h-3 mr-1" /> : <Lock className="w-3 h-3 mr-1" />}
                {deck.isPublic ? 'Public' : 'Private'}
              </span>
            </div>

            {deck.description && (
              <p className="mb-4" style={{ color: "var(--text-secondary, #B8B0D8)" }}>
                {deck.description}
              </p>
            )}

            <div className="flex flex-wrap items-center gap-4 text-sm" style={{ color: "var(--text-secondary, #B8B0D8)" }}>
              <div className="flex items-center gap-1">
                <User className="h-4 w-4" />
                <span>{deck.author?.name || 'Anonymous'}</span>
              </div>
              <div className="flex items-center gap-1">
                <Calendar className="h-4 w-4" />
                <span>{formatDate(deck.createdAt)}</span>
              </div>
              <span
                className="inline-flex items-center text-xs font-semibold px-2.5 py-1 rounded-full"
                style={{ background: "rgba(139, 92, 246, 0.15)", color: "var(--brand-primary, #8B5CF6)", border: "1px solid rgba(139, 92, 246, 0.25)" }}
              >
                {deck.game || deck.gameName || 'Unknown'}
              </span>
              {deck.formatId && (
                <span
                  className="inline-flex items-center text-xs font-medium px-2.5 py-1 rounded-full"
                  style={{ background: "var(--bg-surface-3, #2C2A4A)", color: "var(--text-secondary, #B8B0D8)", border: "1px solid var(--border-default, #2C2A4A)" }}
                >
                  {deck.formatId}
                </span>
              )}
            </div>
          </div>

          {/* Actions */}
          <div className="flex flex-wrap gap-3">
            {isOwner && (
              <Link href={`/decks/${deck.id}/edit`}>
                <button
                  className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-white rounded-[14px] transition-colors"
                  style={{ background: "var(--brand-primary, #8B5CF6)", boxShadow: "0 2px 8px rgba(139, 92, 246, 0.25)" }}
                >
                  <Edit className="h-4 w-4" />
                  Edit Deck
                </button>
              </Link>
            )}

            <Button
              variant="tonal"
              onClick={handleLike}
              disabled={!isAuthenticated}
              className="flex items-center gap-2"
            >
              <Heart className={`h-4 w-4 ${liked ? 'fill-current' : ''}`} style={liked ? { color: "var(--negative, #EF4444)" } : undefined} />
              {likeCount}
            </Button>

            {isAuthenticated && !isOwner && (
              <Button
                variant="tonal"
                onClick={handleCopy}
                className="flex items-center gap-2"
              >
                <Copy className="h-4 w-4" />
                Copy
              </Button>
            )}

            <Button
              variant="tonal"
              onClick={handleShare}
              className="flex items-center gap-2"
            >
              <Share className="h-4 w-4" />
              Share
            </Button>
          </div>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        {[
          { icon: <Layers className="h-4 w-4" />, label: "Cards", value: deck.stats?.totalCards || 0 },
          { icon: <Eye className="h-4 w-4" />, label: "Views", value: deck.stats?.views || 0 },
          { icon: <Copy className="h-4 w-4" />, label: "Copies", value: deck.stats?.copies || 0 },
          ...(deck.pricing ? [{ icon: <DollarSign className="h-4 w-4" />, label: "Value", value: `$${deck.pricing.totalValue?.toFixed(0) || '0'}` }] : []),
        ].map((stat) => (
          <div
            key={stat.label}
            className="rounded-[14px] p-4"
            style={{ background: "var(--bg-surface-1, #18162A)", border: "1px solid var(--border-default, #2C2A4A)" }}
          >
            <div className="flex items-center gap-2 mb-1" style={{ color: "var(--text-tertiary, #7B72A8)" }}>
              {stat.icon}
              <span className="text-sm">{stat.label}</span>
            </div>
            <span className="text-2xl font-bold" style={{ color: "var(--text-primary, #F0EEFF)" }}>
              {stat.value}
            </span>
          </div>
        ))}
      </div>

      {/* Deck Content */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Cover Image */}
        {deck.coverImageUrl && (
          <div className="lg:col-span-1">
            <div
              className="rounded-[14px] p-4"
              style={{ background: "var(--bg-surface-1, #18162A)", border: "1px solid var(--border-default, #2C2A4A)" }}
            >
              <h2 className="text-lg font-semibold mb-4" style={{ color: "var(--text-primary, #F0EEFF)" }}>Cover</h2>
              <div className="aspect-[3/4] rounded-[10px] overflow-hidden" style={{ background: "var(--bg-surface-2, #21203A)" }}>
                <OptimizedImage
                  src={deck.coverImageUrl}
                  alt={deck.name}
                  width={300}
                  height={400}
                  sizes="(max-width: 1024px) 100vw, 33vw"
                  className="object-contain"
                />
              </div>
            </div>
          </div>
        )}

        {/* Cards List */}
        <div className={`${deck.coverImageUrl ? 'lg:col-span-2' : 'lg:col-span-3'}`}>
          <div
            className="rounded-[14px] p-6"
            style={{ background: "var(--bg-surface-1, #18162A)", border: "1px solid var(--border-default, #2C2A4A)" }}
          >
            <h2 className="text-lg font-semibold mb-4" style={{ color: "var(--text-primary, #F0EEFF)" }}>Decklist</h2>

            {deck.cards && deck.cards.length > 0 ? (
              <div className="space-y-4">
                {Object.entries(
                  deck.cards.reduce((zones: any, card: any) => {
                    const zone = card.zone || 'main'
                    if (!zones[zone]) zones[zone] = []
                    zones[zone].push(card)
                    return zones
                  }, {})
                ).map(([zone, cards]: [string, any]) => (
                  <div key={zone}>
                    <h3 className="font-medium capitalize mb-2" style={{ color: "var(--text-primary, #F0EEFF)" }}>
                      {zone} ({cards.reduce((sum: number, card: any) => sum + (card.quantity || 1), 0)})
                    </h3>
                    <div className="space-y-1">
                      {cards.map((card: any) => (
                        <div
                          key={`${card.cardId}-${card.zone}`}
                          className="flex justify-between items-center py-1 px-2 rounded transition-colors"
                          style={{ color: "var(--text-primary, #F0EEFF)" }}
                        >
                          <span>
                            {card.quantity || 1}x {card.name || card.cardName || 'Unknown Card'}
                          </span>
                          {card.manaCost && (
                            <span className="text-sm" style={{ color: "var(--text-tertiary, #7B72A8)" }}>
                              {card.manaCost}
                            </span>
                          )}
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <p className="text-center py-8" style={{ color: "var(--text-secondary, #B8B0D8)" }}>
                No cards in this deck yet.
              </p>
            )}
          </div>
        </div>
      </div>

      {/* Tags */}
      {deck.tags && deck.tags.length > 0 && (
        <div className="mt-8">
          <h2 className="text-lg font-semibold mb-4" style={{ color: "var(--text-primary, #F0EEFF)" }}>Tags</h2>
          <div className="flex flex-wrap gap-2">
            {deck.tags.map((tag: string) => (
              <span
                key={tag}
                className="text-sm px-3 py-1 rounded-full"
                style={{ background: "var(--bg-surface-3, #2C2A4A)", color: "var(--text-secondary, #B8B0D8)" }}
              >
                {tag}
              </span>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import React from 'react'
import { Deck, DeckStats as DeckStatsType } from '@/types/deck'
import { useDeckBuilder } from '@/contexts/DeckBuilderContext'
import { Progress } from '@/components/ui/progress'
import { cn } from '@/lib/utils'
import { DeckErrorBoundary } from './DeckErrorBoundary'
// Removed Recharts imports to avoid compatibility issues with Next.js 15
// Using CSS-based visualizations instead

interface DeckStatsProps {
  deck: Deck
  className?: string
}

function DeckStatsInner({ deck, className }: DeckStatsProps) {
  const { stats, format } = useDeckBuilder()
  
  // Ensure stats exist with defaults
  const safeStats = stats || {
    totalCards: 0,
    mainDeckSize: 0,
    sideboardSize: 0,
    manaCurve: {},
    colorDistribution: {},
    typeDistribution: {},
    rarityDistribution: {}
  }
  
  // Prepare mana curve data
  const manaCurveData = React.useMemo(() => {
    if (!safeStats.manaCurve) return []
    
    return Object.entries(safeStats.manaCurve).map(([cmc, count]) => ({
      cmc: cmc === '7' ? '7+' : cmc,
      count,
    })).sort((a, b) => {
      const aNum = a.cmc === '7+' ? 7 : parseInt(a.cmc)
      const bNum = b.cmc === '7+' ? 7 : parseInt(b.cmc)
      return aNum - bNum
    })
  }, [safeStats.manaCurve])
  
  // Prepare color distribution data
  const colorData = React.useMemo(() => {
    if (!safeStats.colorDistribution) return []
    
    const colorMap: { [key: string]: string } = {
      'W': '#F8F6D8', // White
      'U': '#0E68AB', // Blue
      'B': '#150B00', // Black
      'R': '#D3202A', // Red
      'G': '#00733E', // Green
      'C': '#BFB7B1', // Colorless
    }
    
    return Object.entries(safeStats.colorDistribution).map(([color, count]) => ({
      name: getColorName(color),
      value: count,
      fill: colorMap[color] || '#888888',
    }))
  }, [safeStats.colorDistribution])
  
  // Prepare type distribution data
  const typeData = React.useMemo(() => {
    if (!safeStats.typeDistribution) return []
    
    return Object.entries(safeStats.typeDistribution)
      .map(([type, count]) => ({
        type: simplifyTypeName(type),
        count,
      }))
      .sort((a, b) => b.count - a.count)
      .slice(0, 6) // Show top 6 types
  }, [safeStats.typeDistribution])
  
  // Early return if deck is not available or malformed - AFTER all hooks
  if (!deck || !deck.cards) {
    return (
      <div className={cn('space-y-4 p-4 text-center text-muted-foreground', className)}>
        <div>No deck data available</div>
      </div>
    )
  }
  
  const deckCompleteness = format ? (safeStats.mainDeckSize / format.minDeckSize) * 100 : 0
  
  return (
    <div className={cn('space-y-4', className)}>
      {/* Deck Size Progress */}
      <div className="space-y-2">
        <div className="flex justify-between text-sm">
          <span className="font-medium">Deck Size</span>
          <span className="text-muted-foreground">
            {safeStats.mainDeckSize} / {format?.minDeckSize || 60}
          </span>
        </div>
        <Progress value={Math.min(deckCompleteness, 100)} className="h-2" />
      </div>
      
      {/* Quick Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        <StatCard
          label="Main Deck"
          value={safeStats.mainDeckSize}
          subtext="cards"
        />
        <StatCard
          label="Sideboard"
          value={safeStats.sideboardSize || 0}
          subtext="cards"
        />
        {deck.game === 'MTG' && safeStats.averageCmc !== undefined && (
          <StatCard
            label="Avg CMC"
            value={safeStats.averageCmc.toFixed(2)}
            subtext="mana"
          />
        )}
        <StatCard
          label="Unique Cards"
          value={(deck.cards?.main?.length || 0) + (deck.cards?.sideboard?.length || 0)}
          subtext="different"
        />
      </div>
      
      {/* Mana Curve (MTG only) */}
      {deck.game === 'MTG' && manaCurveData.length > 0 && (
        <div className="space-y-2">
          <h4 className="font-medium text-sm">Mana Curve</h4>
          <div className="space-y-1">
            {manaCurveData.map((item) => (
              <div key={item.cmc} className="flex items-center justify-between">
                <span className="text-xs text-muted-foreground w-8">{item.cmc}</span>
                <div className="flex-1 mx-2">
                  <Progress 
                    value={(item.count / Math.max(...manaCurveData.map(d => d.count))) * 100} 
                    className="h-2" 
                  />
                </div>
                <span className="text-xs font-medium w-6 text-right">{item.count}</span>
              </div>
            ))}
          </div>
        </div>
      )}
      
      {/* Color Distribution (MTG only) */}
      {deck.game === 'MTG' && colorData.length > 0 && (
        <div className="space-y-2">
          <h4 className="font-medium text-sm">Color Distribution</h4>
          <div className="space-y-2">
            {colorData.map((color) => (
              <div key={color.name} className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <div 
                    className="w-3 h-3 rounded-full border"
                    style={{ backgroundColor: color.fill }}
                  />
                  <span className="text-xs">{color.name}</span>
                </div>
                <div className="flex items-center gap-2">
                  <Progress 
                    value={(color.value / safeStats.mainDeckSize) * 100} 
                    className="h-2 w-16" 
                  />
                  <span className="text-xs font-medium w-6 text-right">{color.value}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
      
      {/* Type Distribution */}
      {typeData.length > 0 && (
        <div className="space-y-2">
          <h4 className="font-medium text-sm">Card Types</h4>
          <div className="space-y-1">
            {typeData.map((type) => (
              <div key={type.type} className="flex items-center justify-between">
                <span className="text-xs text-muted-foreground">{type.type}</span>
                <div className="flex items-center gap-2">
                  <Progress 
                    value={(type.count / safeStats.mainDeckSize) * 100} 
                    className="h-1.5 w-20"
                  />
                  <span className="text-xs font-medium w-8 text-right">{type.count}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
      
      {/* Rarity Distribution */}
      {safeStats.rarityDistribution && Object.keys(safeStats.rarityDistribution).length > 0 && (
        <div className="space-y-2">
          <h4 className="font-medium text-sm">Rarity</h4>
          <div className="grid grid-cols-4 gap-2">
            {Object.entries(safeStats.rarityDistribution).map(([rarity, count]) => (
              <div
                key={rarity}
                className="text-center p-2 rounded-md"
                style={getRarityStyle(rarity)}
              >
                <div className="text-xs font-medium">{getRarityLabel(rarity)}</div>
                <div className="text-lg font-bold">{count}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

interface StatCardProps {
  label: string
  value: string | number
  subtext?: string
}

function StatCard({ label, value, subtext }: StatCardProps) {
  return (
    <div className="text-center space-y-1">
      <div className="text-xs text-muted-foreground">{label}</div>
      <div className="text-2xl font-bold">{value}</div>
      {subtext && (
        <div className="text-xs text-muted-foreground">{subtext}</div>
      )}
    </div>
  )
}

function getColorName(code: string): string {
  const colors: { [key: string]: string } = {
    'W': 'White',
    'U': 'Blue',
    'B': 'Black',
    'R': 'Red',
    'G': 'Green',
    'C': 'Colorless',
  }
  return colors[code] || code
}

function simplifyTypeName(type: string): string {
  // Remove unnecessary words and simplify type names
  return type
    .replace('Legendary ', '')
    .replace('Basic ', '')
    .replace('Snow ', '')
    .replace('Tribal ', '')
    .split(' — ')[0]
}

function getRarityStyle(rarity: string): React.CSSProperties {
  const lower = rarity.toLowerCase()
  if (lower === 'mythic' || lower === 'mythic rare') {
    return { border: "1px solid #F97316", background: "rgba(249, 115, 22, 0.1)" }
  }
  if (lower === 'rare') {
    return { border: "1px solid #EAB308", background: "rgba(234, 179, 8, 0.1)" }
  }
  if (lower === 'uncommon') {
    return { border: "1px solid var(--border-default, #2C2A4A)", background: "var(--bg-surface-3, #2C2A4A)" }
  }
  return { border: "1px solid var(--border-default, #2C2A4A)", background: "var(--bg-surface-2, #21203A)" }
}

function getRarityLabel(rarity: string): string {
  const lower = rarity.toLowerCase()
  if (lower === 'mythic' || lower === 'mythic rare') return 'Mythic'
  if (lower === 'rare') return 'Rare'
  if (lower === 'uncommon') return 'Uncommon'
  if (lower === 'common') return 'Common'
  return rarity
}

export function DeckStats(props: DeckStatsProps) {
  return (
    <DeckErrorBoundary fallback={
      <div className={cn('space-y-4 p-4 text-center text-muted-foreground', props.className)}>
        <div>Unable to load deck statistics</div>
      </div>
    }>
      <DeckStatsInner {...props} />
    </DeckErrorBoundary>
  )
}

