import { Metadata } from "next"
import { notFound } from "next/navigation"
import { getBaseURL } from "@/lib/server-utils"
import { DeckViewPage } from "@/components/decks/DeckViewPage"
import { customerBackendAPI } from "@/lib/api/customer-backend"

export async function generateMetadata({ 
  params 
}: { 
  params: Promise<{ locale: string; deckId: string }> 
}): Promise<Metadata> {
  const { deckId } = await params
  const baseUrl = await getBaseURL()
  
  try {
    const deck = await customerBackendAPI.getDeck(deckId)
    
    return {
      title: `${deck.name} | SideDecked`,
      description: `View and analyze the ${deck.name} deck for ${deck.game || 'TCG'}.`,
      openGraph: {
        title: `${deck.name} | SideDecked`,
        description: `${deck.description || `A ${deck.game || 'TCG'} deck with ${deck.stats?.totalCards || 0} cards.`}`,
        url: `${baseUrl}/decks/${deckId}`,
        type: "website",
        images: deck.coverImageUrl ? [{ url: deck.coverImageUrl }] : undefined,
      },
    }
  } catch (error) {
    return {
      title: "Deck | SideDecked",
      description: "View TCG deck details on SideDecked",
    }
  }
}

type Props = {
  params: Promise<{ locale: string; deckId: string }>
}

export default async function DeckPage({ params }: Props) {
  const { deckId } = await params
  
  try {
    const deck = await customerBackendAPI.getDeck(deckId)
    
    if (!deck || (!deck.isPublic && !deck.isOwnedByCurrentUser)) {
      notFound()
    }
    
    return <DeckViewPage deck={deck} />
  } catch (error) {
    console.error('Failed to load deck:', error)
    notFound()
  }
}

