"use client"

import { useState } from "react"
import Link from "next/link"
import { useCustomer } from "@/hooks/useCustomer"
import {
  Heart,
  Copy,
  Share2,
  Edit,
  Download,
  ArrowLeft,
  Globe,
  Lock,
  ShoppingCart,
  User,
  Check,
} from "lucide-react"

interface Props {
  deck: any
  onLike?: () => void
  onCopy?: () => void
  onShare?: () => void
  liked?: boolean
  likeCount?: number
}

export function DeckViewerHeader({
  deck,
  onLike,
  onCopy,
  onShare,
  liked = false,
  likeCount = 0,
}: Props) {
  const { customer, isAuthenticated } = useCustomer()
  const isOwner = isAuthenticated && customer && deck.userId === customer.id

  const formatDate = (date: string | Date) => {
    const d = new Date(date)
    const now = new Date()
    const diff = now.getTime() - d.getTime()
    const days = Math.floor(diff / (1000 * 60 * 60 * 24))
    if (days === 0) return "Today"
    if (days === 1) return "1 day ago"
    if (days < 30) return `${days} days ago`
    return d.toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    })
  }

  const totalCards = deck.stats?.totalCards || 0
  const totalValue = deck.pricing?.totalValue

  return (
    <div data-testid="deck-viewer-header" className="relative overflow-hidden">
      {/* Gradient background */}
      <div
        className="absolute inset-0"
        style={{
          background: `
            linear-gradient(135deg, rgba(167, 139, 250, 0.12) 0%, rgba(139, 92, 246, 0.04) 40%, transparent 70%),
            linear-gradient(to bottom, transparent 60%, var(--bg-base, #09090F) 100%)
          `,
        }}
      />
      <div
        className="absolute -top-20 -right-20 w-[400px] h-[400px]"
        style={{
          background:
            "radial-gradient(circle, rgba(167, 139, 250, 0.08) 0%, transparent 70%)",
        }}
      />

      <div className="relative z-[1] px-6 md:px-12 pt-6 md:pt-12 pb-8 md:pb-12">
        {/* Back link */}
        <Link
          href="/decks"
          className="inline-flex items-center gap-2 mb-6 text-sm transition-colors hover:opacity-80"
          style={{ color: "var(--text-secondary, #B8B0D8)" }}
        >
          <ArrowLeft className="h-4 w-4" />
          Back to Decks
        </Link>

        <div className="flex flex-col lg:flex-row lg:items-start lg:justify-between gap-8">
          {/* Left side — info */}
          <div className="flex-1 max-w-[780px]">
            {/* Badges */}
            <div className="flex flex-wrap gap-2 mb-4">
              <span
                className="font-barlow font-semibold text-xs tracking-wider uppercase px-3.5 py-1.5 rounded-full"
                style={{
                  background: "rgba(167, 139, 250, 0.15)",
                  color: "var(--game-mtg, #A78BFA)",
                  border: "1px solid rgba(167, 139, 250, 0.3)",
                }}
              >
                {deck.game || deck.gameName || "TCG"}
              </span>
              {(deck.formatCode || deck.format || deck.formatId) && (
                <span
                  className="font-barlow font-medium text-xs tracking-wider uppercase px-3.5 py-1.5 rounded-full"
                  style={{
                    color: "var(--text-secondary, #B8B0D8)",
                    border: "1px solid var(--border-strong, #4A4680)",
                    background: "transparent",
                  }}
                >
                  {deck.formatCode || deck.format || deck.formatId}
                </span>
              )}
            </div>

            {/* Deck name */}
            <h1
              className="font-barlow-condensed font-bold leading-tight mb-3"
              style={{
                fontSize: "clamp(32px, 4vw, 44px)",
                color: "var(--text-primary, #F0EEFF)",
                letterSpacing: "-0.01em",
              }}
            >
              {deck.name}
            </h1>

            {/* Author row */}
            <div className="flex items-center gap-2.5 mb-4">
              <div
                className="w-8 h-8 rounded-full flex-shrink-0"
                style={{
                  background: "linear-gradient(135deg, #EF4444, #F59E0B)",
                }}
              />
              <span
                className="font-barlow font-semibold text-sm"
                style={{ color: "var(--text-primary, #F0EEFF)" }}
              >
                by @{deck.author?.name || deck.author?.username || "Anonymous"}
              </span>
              {deck.updatedAt && (
                <span
                  className="text-sm"
                  style={{ color: "var(--text-tertiary, #7B72A8)" }}
                >
                  · Updated {formatDate(deck.updatedAt)}
                </span>
              )}
            </div>

            {/* Description */}
            {deck.description && (
              <p
                className="text-sm leading-relaxed mb-4 max-w-[640px]"
                style={{ color: "var(--text-secondary, #B8B0D8)" }}
              >
                {deck.description}
              </p>
            )}

            {/* Tags */}
            {deck.tags && deck.tags.length > 0 && (
              <div className="flex flex-wrap gap-2">
                {deck.tags.map((tag: string) => (
                  <span
                    key={tag}
                    className="font-medium text-xs px-3 py-1 rounded-full"
                    style={{
                      background: "var(--bg-surface-2, #21203A)",
                      color: "var(--text-secondary, #B8B0D8)",
                      border: "1px solid var(--border-default, #2C2A4A)",
                    }}
                  >
                    {tag}
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Right side — social stats + actions */}
          <div className="flex flex-col items-start lg:items-end gap-4 flex-shrink-0">
            {/* Social stats */}
            <div className="flex items-center gap-5 mb-2">
              <SocialStat icon="♥" count={likeCount} label="likes" />
              <SocialStat
                icon="⚃"
                count={deck.stats?.copies || 0}
                label="copies"
              />
              <SocialStat
                icon="◉"
                count={deck.stats?.views || 0}
                label="views"
              />
              <button
                onClick={onShare}
                className="flex items-center gap-1.5 text-sm px-3.5 py-1.5 rounded-full cursor-pointer transition-colors hover:opacity-80"
                style={{
                  background: "var(--bg-surface-3, #2C2A4A)",
                  color: "var(--text-secondary, #B8B0D8)",
                  border: "1px solid var(--border-default, #2C2A4A)",
                }}
              >
                <Share2 className="w-3.5 h-3.5" />
                Share
              </button>
            </div>

            {/* Action buttons */}
            <div className="flex flex-col gap-2.5 w-full lg:w-[240px]">
              {isAuthenticated && !isOwner && (
                <button
                  onClick={onCopy}
                  className="flex items-center justify-center gap-2 font-barlow font-semibold text-sm px-6 py-3 rounded-[10px] transition-colors text-white cursor-pointer"
                  style={{
                    background: "var(--brand-primary, #8B5CF6)",
                  }}
                >
                  <Copy className="w-4 h-4" />
                  Copy Deck
                </button>
              )}

              {totalValue && (
                <button
                  className="flex items-center justify-center gap-2 font-barlow font-semibold text-sm px-6 py-3 rounded-[10px] transition-colors text-white cursor-pointer"
                  style={{
                    background: "var(--brand-secondary, #FF7849)",
                  }}
                >
                  <ShoppingCart className="w-4 h-4" />
                  Buy All Cards — ${totalValue.toFixed(2)}
                </button>
              )}

              {isOwner && (
                <Link href={`/decks/${deck.id}/edit`}>
                  <button
                    className="w-full flex items-center justify-center gap-2 font-barlow font-semibold text-sm px-6 py-3 rounded-[10px] transition-colors text-white cursor-pointer"
                    style={{
                      background: "var(--brand-primary, #8B5CF6)",
                    }}
                  >
                    <Edit className="w-4 h-4" />
                    Edit Deck
                  </button>
                </Link>
              )}

              <button
                className="flex items-center justify-center gap-2 font-barlow font-medium text-sm px-6 py-2.5 rounded-[10px] transition-colors cursor-pointer"
                style={{
                  background: "transparent",
                  color: "var(--text-secondary, #B8B0D8)",
                  border: "1px solid var(--border-strong, #4A4680)",
                }}
              >
                <Download className="w-3.5 h-3.5" />
                Export
              </button>

              <button
                onClick={onLike}
                disabled={!isAuthenticated}
                className="flex items-center justify-center gap-2 font-barlow font-medium text-sm px-6 py-2.5 rounded-[10px] transition-colors cursor-pointer disabled:opacity-50"
                style={{
                  background: "transparent",
                  color: liked
                    ? "var(--negative, #EF4444)"
                    : "var(--text-secondary, #B8B0D8)",
                  border: `1px solid ${liked ? "rgba(239, 68, 68, 0.3)" : "var(--border-strong, #4A4680)"}`,
                }}
              >
                <Heart
                  className={`w-4 h-4 ${liked ? "fill-current" : ""}`}
                />
                {liked ? "Liked" : "Like"} · {likeCount}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

function SocialStat({
  icon,
  count,
  label,
}: {
  icon: string
  count: number
  label: string
}) {
  const formatted =
    count >= 1000
      ? `${(count / 1000).toFixed(1).replace(/\.0$/, "")}k`
      : String(count)

  return (
    <div
      className="flex items-center gap-1.5 text-sm"
      style={{ color: "var(--text-secondary, #B8B0D8)" }}
    >
      <span className="text-base">{icon}</span>
      <span
        className="font-mono font-medium text-sm"
        style={{ fontFamily: "var(--font-mono, 'DM Mono', monospace)" }}
      >
        {formatted}
      </span>
      <span>{label}</span>
    </div>
  )
}

"use client"

import { useState, useMemo } from "react"
import { OptimizedImage } from "@/components/ui/OptimizedImage"
import { ChevronDown, ChevronRight } from "lucide-react"

interface Props {
  deck: any
}

/** Map a card's type_line to a simplified category */
function getCardCategory(typeLine: string | undefined): string {
  if (!typeLine) return "Other"
  const t = typeLine.toLowerCase()
  if (t.includes("creature")) return "Creatures"
  if (t.includes("instant")) return "Instants"
  if (t.includes("sorcery")) return "Sorceries"
  if (t.includes("enchantment")) return "Enchantments"
  if (t.includes("artifact")) return "Artifacts"
  if (t.includes("planeswalker")) return "Planeswalkers"
  if (t.includes("land")) return "Lands"
  return "Other"
}

/** Get CSS background class for card type */
function getCardTypeGradient(category: string): string {
  switch (category) {
    case "Creatures":
      return "linear-gradient(145deg, #2D1A1A 0%, #1A1020 100%)"
    case "Instants":
      return "linear-gradient(145deg, #1A1A2D 0%, #1A1020 100%)"
    case "Sorceries":
      return "linear-gradient(145deg, #2D1A2D 0%, #1A1020 100%)"
    case "Enchantments":
      return "linear-gradient(145deg, #1A2D2D 0%, #1A1020 100%)"
    case "Artifacts":
      return "linear-gradient(145deg, #2D2D1A 0%, #1A1020 100%)"
    case "Planeswalkers":
      return "linear-gradient(145deg, #2D1A2D 0%, #1A1020 100%)"
    case "Lands":
      return "linear-gradient(145deg, #1A2D1A 0%, #1A1020 100%)"
    default:
      return "linear-gradient(145deg, #1A1A1A 0%, #141020 100%)"
  }
}

/** Priority order for type categories */
const TYPE_ORDER = [
  "Creatures",
  "Planeswalkers",
  "Instants",
  "Sorceries",
  "Enchantments",
  "Artifacts",
  "Lands",
  "Other",
]

interface CardGroup {
  category: string
  cards: any[]
  totalQty: number
}

export function DeckVisualView({ deck }: Props) {
  const [sideboardOpen, setSideboardOpen] = useState(false)

  // Group main deck cards by type
  const mainGroups: CardGroup[] = useMemo(() => {
    const allMainCards = deck.cards?.main || []
    const grouped: Record<string, any[]> = {}

    for (const card of allMainCards) {
      const category = getCardCategory(card.card?.type_line || card.type_line)
      if (!grouped[category]) grouped[category] = []
      grouped[category].push(card)
    }

    return TYPE_ORDER.filter((cat) => grouped[cat]?.length > 0).map((cat) => ({
      category: cat,
      cards: grouped[cat],
      totalQty: grouped[cat].reduce(
        (sum: number, c: any) => sum + (c.quantity || 1),
        0
      ),
    }))
  }, [deck.cards])

  // Sideboard cards
  const sideboardCards = deck.cards?.sideboard || []
  const sideboardQty = sideboardCards.reduce(
    (sum: number, c: any) => sum + (c.quantity || 1),
    0
  )

  return (
    <div data-testid="deck-visual-view" className="px-6 md:px-12 py-8">
      {mainGroups.map((group) => (
        <div key={group.category} className="mb-8">
          <div
            className="flex items-center gap-3 mb-4 pb-2.5"
            style={{ borderBottom: "1px solid var(--border-default, #2C2A4A)" }}
          >
            <span
              className="font-barlow font-semibold text-base"
              style={{ color: "var(--text-primary, #F0EEFF)" }}
            >
              {group.category}
            </span>
            <span
              className="font-mono text-xs px-2.5 py-0.5 rounded-full"
              style={{
                background: "var(--bg-surface-2, #21203A)",
                color: "var(--text-tertiary, #7B72A8)",
                fontFamily: "var(--font-mono, 'DM Mono', monospace)",
              }}
            >
              {group.totalQty}
            </span>
          </div>
          <div className="flex flex-wrap gap-4">
            {group.cards.map((card: any) => (
              <CardTile
                key={`${card.catalogSku || card.card?.id || card.cardId}-${card.zone || "main"}`}
                card={card}
                category={group.category}
              />
            ))}
          </div>
        </div>
      ))}

      {/* Sideboard */}
      {sideboardCards.length > 0 && (
        <div className="mb-8">
          <button
            onClick={() => setSideboardOpen(!sideboardOpen)}
            className="flex items-center gap-2 mb-4 pb-2.5 w-full cursor-pointer"
            style={{ borderBottom: "1px solid var(--border-default, #2C2A4A)" }}
            data-testid="sideboard-toggle"
          >
            {sideboardOpen ? (
              <ChevronDown
                className="w-3 h-3"
                style={{ color: "var(--text-tertiary, #7B72A8)" }}
              />
            ) : (
              <ChevronRight
                className="w-3 h-3"
                style={{ color: "var(--text-tertiary, #7B72A8)" }}
              />
            )}
            <span
              className="font-barlow font-semibold text-base"
              style={{ color: "var(--text-primary, #F0EEFF)" }}
            >
              Sideboard
            </span>
            <span
              className="font-mono text-xs px-2.5 py-0.5 rounded-full"
              style={{
                background: "var(--bg-surface-2, #21203A)",
                color: "var(--text-tertiary, #7B72A8)",
                fontFamily: "var(--font-mono, 'DM Mono', monospace)",
              }}
            >
              {sideboardQty}
            </span>
          </button>
          {sideboardOpen && (
            <div className="flex flex-wrap gap-4">
              {sideboardCards.map((card: any) => (
                <CardTile
                  key={`sb-${card.catalogSku || card.card?.id || card.cardId}`}
                  card={card}
                  category="Sideboard"
                />
              ))}
            </div>
          )}
        </div>
      )}

      {/* Empty state */}
      {mainGroups.length === 0 && sideboardCards.length === 0 && (
        <p
          className="text-center py-12"
          style={{ color: "var(--text-secondary, #B8B0D8)" }}
        >
          No cards in this deck yet.
        </p>
      )}
    </div>
  )
}

function CardTile({
  card,
  category,
}: {
  card: any
  category: string
}) {
  const name = card.card?.name || card.name || card.cardName || "Unknown Card"
  const qty = card.quantity || 1
  const imageUrl = card.card?.image_uris?.normal || card.card?.image_uris?.small
  const gradient = getCardTypeGradient(
    category === "Sideboard"
      ? "Other"
      : category
  )

  return (
    <div className="w-[140px] md:w-[180px]">
      <div
        className="relative rounded-[14px] overflow-hidden transition-transform duration-200 hover:scale-105"
        style={{
          width: "100%",
          aspectRatio: "5/7",
          boxShadow:
            "0 4px 20px rgba(0, 0, 0, 0.4), 0 0 0 1px rgba(255, 255, 255, 0.05)",
        }}
      >
        {/* Quantity badge */}
        {qty > 1 && (
          <span
            className="absolute top-2 right-2 z-[2] font-mono font-medium text-[11px] px-2 py-0.5 rounded-full text-white"
            style={{
              background: "var(--brand-primary, #8B5CF6)",
              fontFamily: "var(--font-mono, 'DM Mono', monospace)",
            }}
          >
            ×{qty}
          </span>
        )}

        {imageUrl ? (
          <OptimizedImage
            src={imageUrl}
            alt={name}
            width={180}
            height={252}
            className="w-full h-full object-cover"
          />
        ) : (
          <div
            className="w-full h-full flex items-center justify-center font-barlow font-medium text-xs text-center p-3 leading-tight"
            style={{
              background: gradient,
              color: "var(--text-secondary, #B8B0D8)",
            }}
          >
            {name}
          </div>
        )}
      </div>
      <div
        className="text-[11px] mt-1.5 text-center whitespace-nowrap overflow-hidden text-ellipsis"
        style={{ color: "var(--text-secondary, #B8B0D8)" }}
      >
        {name}
      </div>
    </div>
  )
}

