      const category = getCardCategory(card.card?.type_line || card.type_line)
      if (!grouped[category]) grouped[category] = []
      grouped[category].push(card)
    }
    return TYPE_ORDER.filter((t) => grouped[t]?.length > 0).map((t) => ({
      type: t,
      cards: grouped[t].sort((a: any, b: any) =>
        (a.card?.name || a.name || "").localeCompare(b.card?.name || b.name || "")
      ),
      totalQty: grouped[t].reduce(
        (sum: number, c: any) => sum + (c.quantity || 1),
        0
      ),
    }))
  }, [mainCards])

  const totalMainQty = mainCards.reduce(
    (sum: number, c: any) => sum + (c.quantity || 1),
    0
  )
  const totalSBQty = sideboardCards.reduce(
    (sum: number, c: any) => sum + (c.quantity || 1),
    0
  )

  return (
    <div data-testid="deck-list-view" className="px-6 md:px-12 py-8">
      <div className="overflow-x-auto">
        <table className="w-full border-collapse" role="table">
          <thead>
            <tr>
              <th
                className="font-barlow font-semibold text-[11px] tracking-wider uppercase text-left px-4 py-2.5"
                style={{
                  color: "var(--text-tertiary, #7B72A8)",
                  borderBottom: "1px solid var(--border-strong, #4A4680)",
                }}
              >
                Qty
              </th>
              <th
                className="font-barlow font-semibold text-[11px] tracking-wider uppercase text-left px-4 py-2.5"
                style={{
                  color: "var(--text-tertiary, #7B72A8)",
                  borderBottom: "1px solid var(--border-strong, #4A4680)",
                }}
              >
                Card Name
              </th>
              <th
                className="font-barlow font-semibold text-[11px] tracking-wider uppercase text-left px-4 py-2.5"
                style={{
                  color: "var(--text-tertiary, #7B72A8)",
                  borderBottom: "1px solid var(--border-strong, #4A4680)",
                }}
              >
                Mana Cost
              </th>
              <th
                className="font-barlow font-semibold text-[11px] tracking-wider uppercase text-left px-4 py-2.5"
                style={{
                  color: "var(--text-tertiary, #7B72A8)",
                  borderBottom: "1px solid var(--border-strong, #4A4680)",
                }}
              >
                Type
              </th>
              <th
                className="font-barlow font-semibold text-[11px] tracking-wider uppercase text-right px-4 py-2.5"
                style={{
                  color: "var(--text-tertiary, #7B72A8)",
                  borderBottom: "1px solid var(--border-strong, #4A4680)",
                }}
              >
                Price
              </th>
            </tr>
          </thead>
          <tbody>
            {mainGroups.map((group) => (
              <TypeGroupRows key={group.type} group={group} />
            ))}

            {/* Sideboard */}
            {sideboardCards.length > 0 && (
              <>
                <tr>
                  <td
                    colSpan={5}
                    className="font-barlow font-semibold text-xs tracking-wider uppercase px-4 py-2"
                    style={{
                      color: "var(--brand-primary, #8B5CF6)",
                      background: "var(--bg-surface-1, #18162A)",
                      borderBottom: "1px solid var(--border-default, #2C2A4A)",
                    }}
                  >
                    Sideboard ({totalSBQty})
                  </td>
                </tr>
                {sideboardCards
                  .sort((a: any, b: any) =>
                    (a.card?.name || a.name || "").localeCompare(
                      b.card?.name || b.name || ""
                    )
                  )
                  .map((card: any) => (
                    <CardRow
                      key={`sb-${card.catalogSku || card.card?.id || card.cardId}`}
                      card={card}
                    />
                  ))}
              </>
            )}

            {/* Total row */}
            <tr>
              <td
                colSpan={4}
                className="font-mono font-medium text-sm px-4 py-3.5"
                style={{
                  color: "var(--brand-primary, #8B5CF6)",
                  borderTop: "2px solid var(--brand-primary, #8B5CF6)",
                  fontFamily: "var(--font-mono, 'DM Mono', monospace)",
                }}
              >
                {totalMainQty + totalSBQty} cards
              </td>
              <td
                className="font-mono font-medium text-sm text-right px-4 py-3.5"
                style={{
                  color: "var(--brand-primary, #8B5CF6)",
                  borderTop: "2px solid var(--brand-primary, #8B5CF6)",
                  fontFamily: "var(--font-mono, 'DM Mono', monospace)",
                }}
              >
                {deck.pricing?.totalValue
                  ? `$${deck.pricing.totalValue.toFixed(2)}`
                  : "—"}
              </td>
            </tr>
          </tbody>
        </table>
      </div>

      {/* Empty state */}
      {mainCards.length === 0 && sideboardCards.length === 0 && (
        <p
          className="text-center py-12"
          style={{ color: "var(--text-secondary, #B8B0D8)" }}
        >
          No cards in this deck yet.
        </p>
      )}
    </div>
  )
}

function TypeGroupRows({ group }: { group: TypeGroup }) {
  return (
    <>
      <tr>
        <td
          colSpan={5}
          className="font-barlow font-semibold text-xs tracking-wider uppercase px-4 py-2"
          style={{
            color: "var(--brand-primary, #8B5CF6)",
            background: "var(--bg-surface-1, #18162A)",
            borderBottom: "1px solid var(--border-default, #2C2A4A)",
          }}
        >
          {group.type} ({group.totalQty})
        </td>
      </tr>
      {group.cards.map((card: any) => (
        <CardRow
          key={`${card.catalogSku || card.card?.id || card.cardId}-${card.zone || "main"}`}
          card={card}
        />
      ))}
    </>
  )
}

function CardRow({ card }: { card: any }) {
  const name = card.card?.name || card.name || card.cardName || "Unknown Card"
  const qty = card.quantity || 1
  const manaCost = card.card?.mana_cost || card.manaCost || "—"
  const typeLine = card.card?.type_line || card.type_line || "—"
  const price = card.price
    ? `$${(card.price * qty).toFixed(2)}`
    : card.card?.price
      ? `$${(card.card.price * qty).toFixed(2)}`
      : "—"

  // Simplify type line for display
  const simpleType = typeLine
    .replace(/Legendary /g, "")
    .replace(/Basic /g, "")
    .split(" — ")[0]

  return (
    <tr>
      <td
        className="font-mono font-medium text-sm px-4 py-2.5"
        style={{
          color: "var(--text-tertiary, #7B72A8)",
          borderBottom: "1px solid var(--border-default, #2C2A4A)",
          fontFamily: "var(--font-mono, 'DM Mono', monospace)",
          width: "48px",
        }}
      >
        {qty}
      </td>
      <td
        className="text-sm px-4 py-2.5"
        style={{
          color: "var(--text-primary, #F0EEFF)",
          borderBottom: "1px solid var(--border-default, #2C2A4A)",
        }}
      >
        {name}
      </td>
      <td
        className="font-mono text-xs px-4 py-2.5"
        style={{
          color: "var(--text-tertiary, #7B72A8)",
          borderBottom: "1px solid var(--border-default, #2C2A4A)",
          fontFamily: "var(--font-mono, 'DM Mono', monospace)",
        }}
      >
        {manaCost}
      </td>
      <td
        className="text-[13px] px-4 py-2.5"
        style={{
          color: "var(--text-tertiary, #7B72A8)",
          borderBottom: "1px solid var(--border-default, #2C2A4A)",
        }}
      >
        {simpleType}
      </td>
      <td
        className="font-mono text-sm text-right px-4 py-2.5"
        style={{
          color: "var(--text-secondary, #B8B0D8)",
          borderBottom: "1px solid var(--border-default, #2C2A4A)",
          fontFamily: "var(--font-mono, 'DM Mono', monospace)",
        }}
      >
        {price}
      </td>
    </tr>
  )
}

"use client"

import { useMemo } from "react"

interface Props {
  manaCurve: Record<string | number, number>
  averageCmc?: number
  className?: string
}

export function ManaCurveChart({ manaCurve, averageCmc, className }: Props) {
  const bars = useMemo(() => {
    // Build 0-6+ bars
    const data: { label: string; count: number }[] = []
    for (let i = 0; i <= 6; i++) {
      if (i === 6) {
        // 6+ bucket: sum everything >= 6
        let total = 0
        for (const [key, val] of Object.entries(manaCurve)) {
          const n = parseInt(key)
          if (n >= 6) total += val
        }
        data.push({ label: "6+", count: total })
      } else {
        data.push({
          label: String(i),
          count: manaCurve[i] || manaCurve[String(i)] || 0,
        })
      }
    }
    return data
  }, [manaCurve])

  const maxCount = Math.max(...bars.map((b) => b.count), 1)

  return (
    <div data-testid="mana-curve-chart" className={className}>
      <div
        className="flex items-end gap-2"
        style={{ height: "120px", paddingTop: "8px" }}
      >
        {bars.map((bar) => {
          const pct = maxCount > 0 ? (bar.count / maxCount) * 100 : 0
          return (
            <div
              key={bar.label}
              className="flex-1 flex flex-col items-center gap-1.5 h-full justify-end"
            >
              <span
                className="text-[10px] font-mono font-medium"
                style={{
                  color: "var(--text-secondary, #B8B0D8)",
                  fontFamily: "var(--font-mono, 'DM Mono', monospace)",
                }}
              >
                {bar.count}
              </span>
              <div
                className="w-full max-w-[36px] rounded-t"
                style={{
                  height: `${pct}%`,
                  minHeight: bar.count > 0 ? "4px" : "0px",
                  background:
                    "linear-gradient(to top, var(--brand-primary, #8B5CF6), rgba(139, 92, 246, 0.5))",
                }}
              />
              <span
                className="text-[11px] font-mono"
                style={{
                  color: "var(--text-tertiary, #7B72A8)",
                  fontFamily: "var(--font-mono, 'DM Mono', monospace)",
                }}
              >
                {bar.label}
              </span>
            </div>
          )
        })}
      </div>
      {averageCmc !== undefined && (
        <div
          className="text-center mt-3 text-sm font-mono"
          style={{
            color: "var(--text-secondary, #B8B0D8)",
            fontFamily: "var(--font-mono, 'DM Mono', monospace)",
          }}
        >
          Avg CMC:{" "}
          <strong style={{ color: "var(--brand-primary, #8B5CF6)", fontWeight: 600 }}>
            {averageCmc.toFixed(1)}
          </strong>
        </div>
      )}
    </div>
  )
}

"use client"

import { useMemo } from "react"
import { ManaCurveChart } from "./ManaCurveChart"

interface Props {
  deck: any
}

const COLOR_MAP: Record<string, { name: string; color: string }> = {
  W: { name: "White", color: "#F8F6D8" },
  U: { name: "Blue", color: "#0E68AB" },
  B: { name: "Black", color: "#150B00" },
  R: { name: "Red", color: "#EF4444" },
  G: { name: "Green", color: "#00733E" },
  C: { name: "Colorless", color: "#6B7280" },
}

function simplifyTypeName(type: string): string {
  return type
    .replace("Legendary ", "")
    .replace("Basic ", "")
    .replace("Snow ", "")
    .split(" — ")[0]
}

export function DeckStatsPanel({ deck }: Props) {
  const stats = deck.stats || {}
  const mainCards = deck.cards?.main || []

  // Compute stats from cards if deck.stats doesn't have them
  const manaCurve = useMemo(() => {
    if (stats.manaCurve && Object.keys(stats.manaCurve).length > 0) {
      return stats.manaCurve
    }
    // Compute from cards
    const curve: Record<number, number> = {}
    for (const card of mainCards) {
      const cmc = card.card?.cmc ?? card.cmc
      if (cmc !== undefined && cmc !== null) {
        const bucket = Math.min(cmc, 7)
        curve[bucket] = (curve[bucket] || 0) + (card.quantity || 1)
      }
    }
    return curve
  }, [stats.manaCurve, mainCards])

  const colorDist = useMemo(() => {
    if (stats.colorDistribution && Object.keys(stats.colorDistribution).length > 0) {
      return stats.colorDistribution
    }
    // Compute from cards
    const dist: Record<string, number> = {}
    for (const card of mainCards) {
      const colors = card.card?.colors || card.colors || []
      const qty = card.quantity || 1
      if (colors.length === 0) {
        dist["C"] = (dist["C"] || 0) + qty
      } else {
        for (const c of colors) {
          dist[c] = (dist[c] || 0) + qty
        }
      }
    }
    return dist
  }, [stats.colorDistribution, mainCards])

  const typeDist = useMemo(() => {
    if (stats.typeDistribution && Object.keys(stats.typeDistribution).length > 0) {
      return stats.typeDistribution
    }
    // Compute from cards
    const dist: Record<string, number> = {}
    for (const card of mainCards) {
      const typeLine = card.card?.type_line || card.type_line || "Other"
      const simplified = simplifyTypeName(typeLine)
      dist[simplified] = (dist[simplified] || 0) + (card.quantity || 1)
    }
    return dist
  }, [stats.typeDistribution, mainCards])

  const totalColorCards = Object.values(colorDist).reduce(
    (sum: number, v: any) => sum + v,
    0
  )
  const totalTypeCards = Object.values(typeDist).reduce(
    (sum: number, v: any) => sum + v,
    0
  )

  const typeEntries = Object.entries(typeDist)
    .map(([type, count]) => ({ type: simplifyTypeName(type), count: count as number }))
    .sort((a, b) => b.count - a.count)
    .slice(0, 8)

  const colorEntries = Object.entries(colorDist)
    .map(([code, count]) => ({
      code,
      name: COLOR_MAP[code]?.name || code,
      color: COLOR_MAP[code]?.color || "#888888",
      count: count as number,
      pct: totalColorCards > 0 ? Math.round(((count as number) / totalColorCards) * 100) : 0,
    }))
    .sort((a, b) => b.count - a.count)

  return (
    <div data-testid="deck-stats-panel" className="px-6 md:px-12 py-8">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Left column */}
        <div className="space-y-6">
          {/* Mana Curve */}
          <StatCard title="Mana Curve">
            <ManaCurveChart
              manaCurve={manaCurve}
              averageCmc={stats.averageCmc}
            />
          </StatCard>

          {/* Color Distribution */}
          {colorEntries.length > 0 && (
            <StatCard title="Color Distribution">
              {/* Stacked bar */}
              <div
                className="h-3 rounded-md overflow-hidden flex mb-2"
              >
                {colorEntries.map((c, i) => (
                  <div
                    key={c.code}
                    style={{
                      width: `${c.pct}%`,
                      background: c.color,
                      borderRadius:
                        i === 0 && colorEntries.length === 1
                          ? "6px"
                          : i === 0
                            ? "6px 0 0 6px"
                            : i === colorEntries.length - 1
                              ? "0 6px 6px 0"
                              : "0",
                    }}
                  />
                ))}
              </div>
              {/* Legend */}
              <div className="flex flex-wrap items-center gap-4">
                {colorEntries.map((c) => (
                  <div
                    key={c.code}
                    className="flex items-center gap-1.5 text-xs"
                    style={{ color: "var(--text-secondary, #B8B0D8)" }}
                  >
                    <div
                      className="w-2 h-2 rounded-full"
                      style={{ background: c.color }}
                    />
                    {c.name} {c.pct}%
                  </div>
                ))}
              </div>
            </StatCard>
          )}

          {/* Type Distribution */}
          {typeEntries.length > 0 && (
            <StatCard title="Type Distribution">
              {typeEntries.map((t) => (
                <div key={t.type} className="flex items-center gap-3 mb-2.5">
                  <span
                    className="text-sm w-20 flex-shrink-0"
                    style={{ color: "var(--text-secondary, #B8B0D8)" }}
                  >
                    {t.type}
                  </span>
                  <div
                    className="flex-1 h-2 rounded overflow-hidden"
                    style={{ background: "var(--bg-surface-3, #2C2A4A)" }}
                  >
                    <div
                      className="h-full rounded"
                      style={{
                        width: `${totalTypeCards > 0 ? (t.count / totalTypeCards) * 100 : 0}%`,
                        background:
                          t.type === "Lands" || t.type === "Land"
                            ? "var(--positive, #10B981)"
                            : "var(--brand-primary, #8B5CF6)",
                      }}
                    />
                  </div>
                  <span
                    className="font-mono text-xs w-7 text-right flex-shrink-0"
                    style={{
                      color: "var(--text-tertiary, #7B72A8)",
                      fontFamily: "var(--font-mono, 'DM Mono', monospace)",
                    }}
                  >
                    {t.count}
                  </span>
                </div>
              ))}
            </StatCard>
          )}
        </div>

        {/* Right column */}
        <div className="space-y-6">
          {/* Win Rate */}
          {deck.winRate !== undefined && (
            <StatCard title="Win Rate">
              <div className="text-center mb-5">
                <div
                  className="font-barlow-condensed font-bold leading-none"
                  style={{
                    fontSize: "56px",
                    color: "var(--positive, #10B981)",
                  }}
                >
                  {deck.winRate}%
                </div>
                {deck.matchCount && (
                  <div
                    className="font-barlow text-sm mt-1"
                    style={{ color: "var(--text-tertiary, #7B72A8)" }}
                  >
                    across {deck.matchCount.toLocaleString()} recorded matches
                  </div>
                )}
              </div>
            </StatCard>
          )}

          {/* Tournament Results */}
          {deck.tournamentResults && deck.tournamentResults.length > 0 && (
            <StatCard title="Tournament Results">
              <ul className="space-y-0">
                {deck.tournamentResults.map(
                  (result: any, i: number) => (
                    <li
                      key={i}
                      className="flex items-center gap-2.5 py-2.5 text-sm"
                      style={{
                        color: "var(--text-secondary, #B8B0D8)",
                        borderBottom:
                          i < deck.tournamentResults.length - 1
                            ? "1px solid var(--border-default, #2C2A4A)"
                            : "none",
                      }}
                    >
                      <span
                        className="w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0"
                        style={
                          result.placement <= 1
                            ? {
                                background: "rgba(245, 158, 11, 0.2)",
                                color: "#F59E0B",
                              }
                            : {
                                background: "rgba(156, 163, 175, 0.2)",
                                color: "#9CA3AF",
                              }
                        }
                      >
                        {result.placement}
                      </span>
                      <span>{result.name}</span>
                    </li>
                  )
                )}
              </ul>
            </StatCard>
          )}

          {/* Meta Position */}
          {(deck.tier || deck.metaShare) && (
            <StatCard title="Meta Position">
              <div className="flex items-center gap-3 mb-4">
                {deck.tier && (
                  <span
                    className="font-barlow font-medium text-xs px-3.5 py-1.5 rounded-full"
                    style={{
                      borderColor: "rgba(245, 158, 11, 0.3)",
                      border: "1px solid rgba(245, 158, 11, 0.3)",
                      color: "var(--warning, #F59E0B)",
                      background: "rgba(245, 158, 11, 0.08)",
                    }}
                  >
                    {deck.tier}
                  </span>
                )}
                {deck.metaShare && (
                  <span
                    className="text-sm"
                    style={{ color: "var(--text-secondary, #B8B0D8)" }}
                  >
                    {deck.metaShare}% of meta
                  </span>
                )}
              </div>
            </StatCard>
          )}

          {/* Format Legality */}
          {deck.legality && Object.keys(deck.legality).length > 0 && (
            <StatCard title="Format Legality">
              <div className="flex flex-wrap gap-2">
                {Object.entries(deck.legality).map(
                  ([format, legal]: [string, any]) => (
                    <span
                      key={format}
                      className="font-barlow font-medium text-xs px-3.5 py-1.5 rounded-full"
                      style={
                        legal
                          ? {
                              border: "1px solid rgba(16, 185, 129, 0.3)",
                              color: "var(--positive, #10B981)",
                              background: "rgba(16, 185, 129, 0.08)",
                            }
                          : {
                              border: "1px solid rgba(239, 68, 68, 0.3)",
                              color: "var(--negative, #EF4444)",
                              background: "rgba(239, 68, 68, 0.08)",
                            }
                      }
                    >
                      {format}
                    </span>
                  )
                )}
              </div>
            </StatCard>
          )}

          {/* Quick stats fallback when no rich meta data */}
          {!deck.winRate && !deck.tournamentResults && !deck.tier && (
            <StatCard title="Quick Stats">
              <div className="grid grid-cols-2 gap-4">
                <QuickStat
                  label="Main Deck"
                  value={stats.mainDeckSize || mainCards.reduce((s: number, c: any) => s + (c.quantity || 1), 0)}
                />
                <QuickStat
                  label="Sideboard"
                  value={stats.sideboardSize || (deck.cards?.sideboard || []).reduce((s: number, c: any) => s + (c.quantity || 1), 0)}
                />
                {stats.averageCmc !== undefined && (
                  <QuickStat
                    label="Avg CMC"
                    value={stats.averageCmc.toFixed(2)}
                  />
                )}
                <QuickStat
                  label="Unique Cards"
                  value={
                    (deck.cards?.main?.length || 0) +
                    (deck.cards?.sideboard?.length || 0)
                  }
                />
              </div>
            </StatCard>
          )}

          {/* Pricing summary */}
          {deck.pricing?.totalValue && (
            <StatCard title="Pricing Summary">
              <div className="text-center">
                <div
                  className="font-barlow-condensed font-bold leading-none"
                  style={{
                    fontSize: "36px",
                    color: "var(--text-primary, #F0EEFF)",
                  }}
                >
                  ${deck.pricing.totalValue.toFixed(2)}
                </div>
                <div
                  className="font-barlow text-sm mt-1"
                  style={{ color: "var(--text-tertiary, #7B72A8)" }}
                >
                  estimated total value
                </div>
              </div>
            </StatCard>
          )}
        </div>
      </div>
    </div>
  )
}

function StatCard({
  title,
  children,
}: {
  title: string
  children: React.ReactNode
}) {
  return (
    <div
      className="rounded-[14px] p-6"
      style={{
        background: "var(--bg-surface-1, #18162A)",
        border: "1px solid var(--border-default, #2C2A4A)",
      }}
    >
      <div
        className="font-barlow font-semibold text-[13px] tracking-wider uppercase mb-4"
        style={{ color: "var(--text-tertiary, #7B72A8)" }}
      >
        {title}
      </div>
      {children}
    </div>
  )
}

function QuickStat({
  label,
  value,
}: {
  label: string
  value: string | number
}) {
  return (
    <div className="text-center space-y-1">
      <div
        className="text-xs"
        style={{ color: "var(--text-tertiary, #7B72A8)" }}
      >
        {label}
      </div>
      <div
        className="text-2xl font-bold"
        style={{ color: "var(--text-primary, #F0EEFF)" }}
      >
        {value}
      </div>
    </div>
  )
}

"use client"

import { useState } from "react"
import { useCustomer } from "@/hooks/useCustomer"
import { DeckViewerHeader } from "./DeckViewerHeader"
import { DeckVisualView } from "./DeckVisualView"
import { DeckListView } from "./DeckListView"
import { DeckStatsPanel } from "./DeckStatsPanel"

interface Props {
  deck: any
}

const TABS = [
  { id: "visual", label: "Visual" },
  { id: "list", label: "List" },
  { id: "stats", label: "Stats" },
] as const

type TabId = (typeof TABS)[number]["id"]

export function DeckViewPage({ deck }: Props) {
  const [activeTab, setActiveTab] = useState<TabId>("visual")
  const [liked, setLiked] = useState(false)
  const [likeCount, setLikeCount] = useState(deck.stats?.likes || 0)
  const { isAuthenticated } = useCustomer()

  const handleLike = async () => {
    if (!isAuthenticated) return
    try {
      setLiked(!liked)
      setLikeCount((prev: number) => (liked ? prev - 1 : prev + 1))
    } catch (error) {
      setLiked(!liked)
      setLikeCount((prev: number) => (liked ? prev + 1 : prev - 1))
      console.error("Failed to update like:", error)
    }
  }

  const handleCopy = async () => {
    if (!isAuthenticated) return
    try {
      console.log("Copy deck:", deck.id)
    } catch (error) {
      console.error("Failed to copy deck:", error)
    }
  }

  const handleShare = async () => {
    if (typeof navigator !== "undefined" && navigator.share) {
      try {
        await navigator.share({
          title: deck.name,
          text: deck.description || `Check out this ${deck.game} deck`,
          url: window.location.href,
        })
      } catch {
        // User cancelled
      }
    } else if (typeof navigator !== "undefined" && navigator.clipboard) {
      try {
        await navigator.clipboard.writeText(window.location.href)
      } catch (error) {
        console.error("Failed to copy URL:", error)
      }
    }
  }

  return (
    <div
      data-testid="deck-view-page"
      style={{ background: "var(--bg-base, #09090F)" }}
    >
      {/* Hero header */}
      <DeckViewerHeader
        deck={deck}
        onLike={handleLike}
        onCopy={handleCopy}
        onShare={handleShare}
        liked={liked}
        likeCount={likeCount}
      />

      {/* Tab navigation — sticky */}
      <div
        data-testid="deck-viewer-tabs"
        className="flex items-center gap-0 px-6 md:px-12 h-[52px] relative z-[15]"
        style={{
          background: "rgba(9, 9, 15, 0.8)",
          backdropFilter: "blur(20px)",
          WebkitBackdropFilter: "blur(20px)",
          borderBottom: "1px solid var(--border-default, #2C2A4A)",
          borderTop: "1px solid var(--border-default, #2C2A4A)",
          position: "sticky",
          top: 0,
        }}
      >
        {TABS.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className="font-barlow font-medium text-sm px-6 h-full flex items-center relative cursor-pointer transition-colors"
            style={{
              color:
                activeTab === tab.id
                  ? "var(--brand-primary, #8B5CF6)"
                  : "var(--text-tertiary, #7B72A8)",
              fontWeight: activeTab === tab.id ? 600 : 500,
              background: "transparent",
              border: "none",
            }}
            data-testid={`tab-${tab.id}`}
          >
            {tab.label}
            {activeTab === tab.id && (
              <span
                className="absolute bottom-0 left-6 right-6 h-0.5 rounded-t"
                style={{
                  background: "var(--brand-primary, #8B5CF6)",
                }}
              />
            )}
          </button>
        ))}
      </div>

      {/* Tab content */}
      <div>
        {activeTab === "visual" && <DeckVisualView deck={deck} />}
        {activeTab === "list" && <DeckListView deck={deck} />}
        {activeTab === "stats" && <DeckStatsPanel deck={deck} />}
      </div>
    </div>
  )
}

