import { DeckViewPage } from "../DeckViewPage"

const mockDeck = {
  id: "deck-1",
  name: "Mono Red Burn",
  description: "A blazing-fast aggro deck",
  game: "MTG",
  format: "Modern",
  formatCode: "modern",
  isPublic: true,
  isValid: true,
  userId: "user-2",
  tags: ["Aggro", "Burn"],
  createdAt: new Date("2026-01-15"),
  updatedAt: new Date("2026-03-10"),
  stats: {
    totalCards: 60,
    mainDeckSize: 60,
    sideboardSize: 15,
    likes: 342,
    views: 1200,
    copies: 89,
    manaCurve: { 1: 28, 2: 16, 3: 8 },
    colorDistribution: { R: 42 },
    typeDistribution: { Creature: 12, Instant: 16, Sorcery: 12, Land: 18 },
  },
  cards: {
    main: [
      {
        catalogSku: "sku-1",
        card: {
          id: "card-1",
          name: "Lightning Bolt",
          game: "MTG",
          mana_cost: "{R}",
          cmc: 1,
          type_line: "Instant",
          colors: ["R"],
        },
        quantity: 4,
        zone: "main" as const,
      },
      {
        catalogSku: "sku-2",
        card: {
          id: "card-2",
          name: "Goblin Guide",
          game: "MTG",
          mana_cost: "{R}",
          cmc: 1,
          type_line: "Creature — Goblin Scout",
          colors: ["R"],
        },
        quantity: 4,
        zone: "main" as const,
      },
    ],
    sideboard: [
      {
        catalogSku: "sku-3",
        card: {
          id: "card-3",
          name: "Smash to Smithereens",
          game: "MTG",
          mana_cost: "{1}{R}",
          cmc: 2,
          type_line: "Instant",
          colors: ["R"],
        },
        quantity: 3,
        zone: "sideboard" as const,
      },
    ],
  },
  author: { name: "pyromancer99" },
}

describe("DeckViewPage", () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it("renders the deck view page container", () => {
    render(<DeckViewPage deck={mockDeck} />)
    expect(screen.getByTestId("deck-view-page")).toBeInTheDocument()
  })

  it("renders the deck viewer header", () => {
    render(<DeckViewPage deck={mockDeck} />)
    expect(screen.getByTestId("deck-viewer-header")).toBeInTheDocument()
    expect(screen.getByText(/Mono Red Burn/)).toBeInTheDocument()
  })

  it("renders tab navigation with Visual, List, Stats tabs", () => {
    render(<DeckViewPage deck={mockDeck} />)
    expect(screen.getByTestId("deck-viewer-tabs")).toBeInTheDocument()
    expect(screen.getByTestId("tab-visual")).toBeInTheDocument()
    expect(screen.getByTestId("tab-list")).toBeInTheDocument()
    expect(screen.getByTestId("tab-stats")).toBeInTheDocument()
  })

  it("shows visual view by default", () => {
    render(<DeckViewPage deck={mockDeck} />)
    expect(screen.getByTestId("deck-visual-view")).toBeInTheDocument()
    expect(screen.queryByTestId("deck-list-view")).not.toBeInTheDocument()
    expect(screen.queryByTestId("deck-stats-panel")).not.toBeInTheDocument()
  })

  it("switches to list view when List tab is clicked", () => {
    render(<DeckViewPage deck={mockDeck} />)
    fireEvent.click(screen.getByTestId("tab-list"))
    expect(screen.getByTestId("deck-list-view")).toBeInTheDocument()
    expect(screen.queryByTestId("deck-visual-view")).not.toBeInTheDocument()
    expect(screen.queryByTestId("deck-stats-panel")).not.toBeInTheDocument()
  })

  it("switches to stats panel when Stats tab is clicked", () => {
    render(<DeckViewPage deck={mockDeck} />)
    fireEvent.click(screen.getByTestId("tab-stats"))
    expect(screen.getByTestId("deck-stats-panel")).toBeInTheDocument()
    expect(screen.queryByTestId("deck-visual-view")).not.toBeInTheDocument()
    expect(screen.queryByTestId("deck-list-view")).not.toBeInTheDocument()
  })

  it("can switch back to visual view after visiting another tab", () => {
    render(<DeckViewPage deck={mockDeck} />)
    fireEvent.click(screen.getByTestId("tab-stats"))
    expect(screen.getByTestId("deck-stats-panel")).toBeInTheDocument()

    fireEvent.click(screen.getByTestId("tab-visual"))
    expect(screen.getByTestId("deck-visual-view")).toBeInTheDocument()
  })

  it("passes like state to header and handles like toggle", () => {
    render(<DeckViewPage deck={mockDeck} />)
    const likeBtn = screen.getByTestId("like-btn")
    expect(likeBtn).toHaveTextContent("Like (342)")

    fireEvent.click(likeBtn)
    expect(likeBtn).toHaveTextContent("Like (343)")
  })

  it("renders with data-testid attributes for inspection", () => {
    render(<DeckViewPage deck={mockDeck} />)
    expect(screen.getByTestId("deck-view-page")).toBeInTheDocument()
    expect(screen.getByTestId("deck-viewer-header")).toBeInTheDocument()
    expect(screen.getByTestId("deck-viewer-tabs")).toBeInTheDocument()
  })
})

